module RefModule (
	input clk,
	input reset,
	input load,
	input [7:0] data_in,
	output reg data_out
);reg [7:0] unused_shift_reg;

always @(posedge clk) begin
	if (reset)
		unused_shift_reg <= 8'b00000000;
	else if (load)
		unused_shift_reg <= data_in;
	else
		unused_shift_reg <= unused_shift_reg >> 1;
end

always @(unused_shift_reg) begin
	data_out <= unused_shift_reg[0];
end

endmodule
